-- Danh sách nguyên liệu thật của quán, lấy từ mockup Kiểm kê kho
-- (design/kiem_ke_kho_mockup_desktop). Đưa vào DB để màn Kiểm kê có sẵn đủ mục.
--
-- stock_qty khởi tạo = số "tồn lý thuyết" ghi trong mockup, để phiếu kiểm kê có
-- số hệ thống thật mà đối chiếu. Bỏ qua tên đã có sẵn (WHERE NOT EXISTS) nên
-- không đụng 7 nguyên liệu seed cũ đang gắn công thức POS, và chạy lại vẫn an toàn.

-- Hai đơn vị mockup dùng mà chưa có trong bảng units.
INSERT INTO units (id, code, name, conversion_factor, is_active)
SELECT * FROM (VALUES
  ('0b000001-0000-4000-8000-00000000000b'::uuid, 'bình', 'Bình', 1, true),
  ('0b000001-0000-4000-8000-00000000000c'::uuid, 'bịch', 'Bịch', 1, true)
) AS v(id, code, name, conversion_factor, is_active)
WHERE NOT EXISTS (SELECT 1 FROM units u WHERE u.code = v.code);

